const axios = require("axios");

const app = express();
const PORT = 3000;

// In-memory cache: maps NIN string -> verification result
const ninCache = new Map();

app.use(express.json());

app.post("/api/verify-nin", async (req, res) => {
  const { nin } = req.body;

  if (!nin) {
    return res.status(400).json({ error: "nin is required" });
  }

  // Return cached result if available
  if (ninCache.has(nin)) {
    return res.json({ cached: true, data: ninCache.get(nin) });
  }

  const appId = process.env.PREMBLY_APP_ID;
  const apiKey = process.env.PREMBLY_API_KEY;

  if (!appId || !apiKey) {
    return res
      .status(500)
      .json({ error: "Prembly credentials are not configured" });
  }

  try {
    const response = await axios.post(
      "https://api.prembly.com/verification/nin",
      { number: nin },
      {
        headers: {
          "app-id": appId,
          "x-api-key": apiKey,
          "Content-Type": "application/json",
        },
      }
    );

    const result = response.data;

    // Cache the successful response
    ninCache.set(nin, result);

    return res.json({ cached: false, data: result });
  } catch (err) {
    const status = err.response?.status || 500;
    const message = err.response?.data || { error: "Prembly API request failed" };
    return res.status(status).json(message);
  }
});

app.listen(PORT, () => {
  console.log(`NIN lookup server running on port ${PORT}`);
});
